import json, re
cp3=json.load(open("/workspace/POLARIS/outputs/s3_gear/cp3_basket_snapshot.json"))
try:
    cp2=json.load(open("/workspace/s2s3_wt/outputs/s2s3_iter1/s2/cp2_corpus_snapshot.json"))
    ev=cp2["evidence_for_gen"]
except Exception as e:
    print("cp2 err", e); ev=[]
_pre=re.compile(r"^(?:doi:|https?://(?:dx\.)?doi\.org/)", re.I)
def nd(x):
    t=str(x or "").strip().lower()
    if not t: return ""
    t=_pre.sub("",t).strip().rstrip("/")
    return t if t.startswith("10.") else ""
doi_by_ev={str(r.get("evidence_id")): nd(r.get("doi")) for r in ev}
print("rows with usable DOI:", sum(1 for v in doi_by_ev.values() if v), "/", len(ev))
swg=cp3["payload"].get("same_work_groups") or []
# map ev -> group key
from collections import defaultdict
doi_to_groupkeys=defaultdict(set)
claimed=set()
for g in swg:
    k=str(g.get("same_work_id"))
    for e in (g.get("member_evidence_ids") or []):
        claimed.add(str(e))
        d=doi_by_ev.get(str(e),"")
        if d: doi_to_groupkeys[d].add(k)
multi={d:ks for d,ks in doi_to_groupkeys.items() if len(ks)>=2}
print("DOIs spanning >=2 distinct cp3 groups:", len(multi))
for d,ks in list(multi.items())[:10]: print(" ", d, "->", ks)
# also: same-DOI pairs where both rows UNclaimed (fold handles) vs one claimed
un=defaultdict(list)
for e,d in doi_by_ev.items():
    if d: un[d].append(e)
split=0; mixed=0
for d,es in un.items():
    if len(es)<2: continue
    c=[e for e in es if e in claimed]
    if len({k for e in c for k in []})>=0: pass
    ks={ }
    stamped=set()
    for g in swg:
        mem=set(map(str,g.get("member_evidence_ids") or []))
        if mem & set(es): stamped.add(str(g.get("same_work_id")))
    if len(stamped)>=2: split+=1
print("same-DOI multi-row sets whose members sit in >=2 cp3 groups:", split)
EOF
